import { Component, OnInit, computed, signal } from '@angular/core';
import { CommonModule } from '@angular/common';
import { RouterLink } from '@angular/router';
import { ApiService } from '../../core/api.service';
import { EventItem } from '../../core/models';

interface DateGroup {
  key: string;
  label: string;
  events: EventItem[];
}

/**
 * GatherUp home — public landing showing upcoming events grouped by date.
 * Loads live data via ApiService.listEvents(undefined, undefined, true) in ngOnInit().
 */
@Component({
  selector: 'app-home',
  standalone: true,
  imports: [CommonModule, RouterLink],
  templateUrl: './home.component.html',
  styleUrl: './home.component.css',
})
export class HomeComponent implements OnInit {
  readonly loading = signal(false);
  readonly error = signal<string | null>(null);

  readonly events = signal<EventItem[]>([]);

  constructor(private api: ApiService) {}

  readonly groups = computed<DateGroup[]>(() => {
    const map = new Map<string, DateGroup>();
    for (const ev of [...this.events()].sort((a, b) => a.startsAt.localeCompare(b.startsAt))) {
      const d = new Date(ev.startsAt);
      const key = ev.startsAt.slice(0, 10);
      if (!map.has(key)) {
        map.set(key, {
          key,
          label: d.toLocaleDateString(undefined, {
            weekday: 'long', month: 'long', day: 'numeric',
          }),
          events: [],
        });
      }
      map.get(key)!.events.push(ev);
    }
    return [...map.values()];
  });

  ngOnInit(): void {
    this.loading.set(true);
    this.error.set(null);
    this.api.listEvents(undefined, undefined, true).subscribe({
      next: (events) => {
        this.events.set(events);
        this.loading.set(false);
      },
      error: () => {
        this.error.set('Could not load events. Please try again.');
        this.loading.set(false);
      },
    });
  }

  spotsLeft(ev: EventItem): number {
    return Math.max(0, ev.capacity - (ev.confirmedCount ?? 0));
  }

  timeLabel(iso: string): string {
    return new Date(iso).toLocaleTimeString(undefined, { hour: 'numeric', minute: '2-digit' });
  }
}
